template.template_css:
@page { size: letter portrait; }

.sev-badge {
    display: inline-block;
    padding: var(--badge-padding);
    border-radius: var(--badge-radius);
    font-size: var(--badge-font-size);
    font-weight: 600;
    text-align: center;
    white-space: nowrap;
}
.sev-critical    { background-color: #dc3545; color: #fff; }
.sev-important   { background-color: #fd7e14; color: #fff; }
.sev-moderate    { background-color: #ffc107; color: #333; }
.sev-low         { background-color: #28a745; color: #fff; }
.sev-unspecified { background-color: #6c757d; color: #fff; }
.sev-n-a,
.sev-unknown     { background-color: #adb5bd; color: #333; }

table.vt th:nth-child(1), table.vt td:nth-child(1) { width: 180px; min-width: 140px; }
table.vt th:nth-child(2), table.vt td:nth-child(2) { min-width: 280px; }
table.vt th:nth-child(3), table.vt td:nth-child(3) { width: 100px; text-align: center; }
table.vt th:nth-child(4), table.vt td:nth-child(4) { width: 120px; text-align: center; }

template.template_md:
{% block header_title %}<h1>Windows Updates Not Installed</h1>
<div class="row-count" style="font-size:13px; opacity:0.85;">
    Filtered: <strong><span id="visibleCount">0</span></strong>
    of <span id="totalCount">0</span>
</div>{% endblock %}

{% block content %}
<script id="data-json" type="application/json">
[
{% set filtered_items = data_sources.allFieldsWindowsUpdates|selectattr('installed', 'ne', True)|list %}
{% for item in filtered_items %}
  {
    "device": {{ item.agent__hostname | default('N/A', true) | tojson }},
    "title": {{ item.title | default('N/A', true) | tojson }},
    "installed": {{ item.installed | default(false) | tojson }},
    "severity": {{ item.severity | default('N/A', true) | tojson }},
    "severityHTML": {{ ('<span class=\"sev-badge sev-' + (item.severity | default('unknown') | lower | replace(' ', '-')) + '\">' + (item.severity | default('N/A', true)) + '</span>') | tojson }}
  }{{ ',' if not loop.last else '' }}
{% endfor %}
]
</script>

<div id="loading">Loading...</div>

<div class="table-wrap" id="tableWrap" style="display:none">
  <table class="vt" id="updatesTable">
    <thead id="tableHead"></thead>
    <tbody id="tableBody"></tbody>
  </table>
</div>

<script>
var columns = [
  {
    id: 'device',
    title: 'Device Name',
    filter: true,
    selectable: true,
    sortable: true
  },
  {
    id: 'title',
    title: 'Update Title',
    filter: true,
    selectable: false,
    sortable: true
  },
  {
    id: 'installed',
    title: 'Installed',
    filter: true,
    selectable: true,
    sortable: true
  },
  {
    id: 'severityHTML',
    title: 'Severity',
    html: true,
    filter: true,
    selectable: true,
    sortable: true,
    filterKey: 'severity'
  }
];

var data = JSON.parse(document.getElementById('data-json').textContent || '[]');

buildHeader();
renderBody();
updateCount();

document.getElementById('loading').style.display = 'none';
document.getElementById('tableWrap').style.display = 'block';
</script>
{% endblock %}
